// // (1) reset: Resets register to 32'b1. Synchronous active low.
// (2) increment: If low, decrements register by 1.
// (3) q: The contents of the register.
module top_module(
	input clk,
	input reset,
	input increment,
	output reg [31:0] q);always @(posedge clk) begin
		if (reset)
			q <= 32'b0;
		else if (increment)
			q <= q + 1;
	end
endmodule

